import{c as t,cG as d,cb as r,c8 as e,cf as s,cT as o,ce as a}from"./chunks/framework.BlkIsu1j.js";const c=JSON.parse('{"title":"附录 B. 标准扩展指令速查表","description":"","frontmatter":{"title":"附录 B. 标准扩展指令速查表","outline":"deep","layout":"doc","prev":{"text":"附录 A. RV64I 基础指令速查表","link":"/lang/assembly/appendix_a_rv64i_reference"},"next":{"text":"附录 C. 伪指令速查表","link":"/lang/assembly/appendix_c_pseudo_instructions"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/appendix_b_extensions_reference.md","filePath":"lang/assembly/appendix_b_extensions_reference.md","lastUpdated":1780203693000}'),f={id:"frontmatter-title",tabindex:"-1"};const h=t({name:"lang/assembly/appendix_b_extensions_reference.md"},[["render",function(t,c,h,n,i,l){return d(),r("div",null,[e("h1",f,[s(o(t.$frontmatter.title)+" ",1),c[0]||(c[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),c[1]||(c[1]=a('<p>RISC-V 标准扩展在 RV64I 基础上增加了乘法除法（M）、原子操作（A）、单/双精度浮点（F/D）、压缩指令（C）等功能。本章提供所有标准扩展的完整指令速查表。</p><hr><h2 id="m-扩展-乘除法" tabindex="-1">M 扩展：乘除法 <a class="header-anchor" href="#m-扩展-乘除法" aria-label="Permalink to “M 扩展：乘除法”">​</a></h2><p>所有 M 扩展指令均为 R-type。乘法指令 opcode=0110011，funct7=0000001。除法指令 opcode=0110011，funct7=0000001。</p><h3 id="标准乘除法-64-位操作" tabindex="-1">标准乘除法（64 位操作） <a class="header-anchor" href="#标准乘除法-64-位操作" aria-label="Permalink to “标准乘除法（64 位操作）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>mul rd, rs1, rs2</code></td><td>rd = (rs1 * rs2)[63:0]（低 64 位）</td><td>000</td></tr><tr><td><code>mulh rd, rs1, rs2</code></td><td>rd = (rs1 * rs2)[127:64]（有符号乘高 64 位）</td><td>001</td></tr><tr><td><code>mulhsu rd, rs1, rs2</code></td><td>rd = (有符号 rs1 * 无符号 rs2)[127:64]</td><td>010</td></tr><tr><td><code>mulhu rd, rs1, rs2</code></td><td>rd = (rs1 * rs2)[127:64]（无符号乘高 64 位）</td><td>011</td></tr><tr><td><code>div rd, rs1, rs2</code></td><td>rd = rs1 / rs2（有符号，向零舍入）</td><td>100</td></tr><tr><td><code>divu rd, rs1, rs2</code></td><td>rd = rs1 / rs2（无符号）</td><td>101</td></tr><tr><td><code>rem rd, rs1, rs2</code></td><td>rd = rs1 % rs2（有符号，向零舍入）</td><td>110</td></tr><tr><td><code>remu rd, rs1, rs2</code></td><td>rd = rs1 % rs2（无符号）</td><td>111</td></tr></tbody></table><blockquote><p><strong>除零行为</strong>：除法结果为 -1（~0），取余结果为被除数。不产生异常。</p></blockquote><h3 id="rv64i-w-变体-32-位操作-opcode-0111011-funct7-0000001" tabindex="-1">RV64I W 变体（32 位操作，opcode=0111011，funct7=0000001） <a class="header-anchor" href="#rv64i-w-变体-32-位操作-opcode-0111011-funct7-0000001" aria-label="Permalink to “RV64I W 变体（32 位操作，opcode=0111011，funct7=0000001）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th></tr></thead><tbody><tr><td><code>mulw rd, rs1, rs2</code></td><td>rd = sign_extend((rs1 * rs2)[31:0])</td><td>000</td></tr><tr><td><code>divw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] / rs2[31:0])</td><td>100</td></tr><tr><td><code>divuw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] /u rs2[31:0])</td><td>101</td></tr><tr><td><code>remw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] % rs2[31:0])</td><td>110</td></tr><tr><td><code>remuw rd, rs1, rs2</code></td><td>rd = sign_extend(rs1[31:0] %u rs2[31:0])</td><td>111</td></tr></tbody></table><hr><h2 id="a-扩展-原子操作" tabindex="-1">A 扩展：原子操作 <a class="header-anchor" href="#a-扩展-原子操作" aria-label="Permalink to “A 扩展：原子操作”">​</a></h2><p>所有 A 扩展指令 opcode=0101111。分为 LR/SC（加载保留/条件存储）和 AMO（原子内存操作）两类。</p><h3 id="lr-sc-opcode-0101111" tabindex="-1">LR/SC（opcode=0101111） <a class="header-anchor" href="#lr-sc-opcode-0101111" aria-label="Permalink to “LR/SC（opcode=0101111）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct3</th><th>funct7</th></tr></thead><tbody><tr><td><code>lr.w rd, (rs1)</code></td><td>rd = M[rs1][31:0]; 设置保留位（32 位）</td><td>010</td><td>00010xx</td></tr><tr><td><code>lr.d rd, (rs1)</code></td><td>rd = M[rs1][63:0]; 设置保留位（64 位）</td><td>011</td><td>00010xx</td></tr><tr><td><code>sc.w rd, rs2, (rs1)</code></td><td>若保留位有效：M[rs1][31:0]=rs2[31:0], rd=0; 否则 rd=1</td><td>010</td><td>00011xx</td></tr><tr><td><code>sc.d rd, rs2, (rs1)</code></td><td>若保留位有效：M[rs1][63:0]=rs2, rd=0; 否则 rd=1</td><td>011</td><td>00011xx</td></tr></tbody></table><blockquote><p><strong>说明</strong>：LR（Load-Reserved）在读取时设置硬件保留位；SC（Store-Conditional）仅在保留位仍有效时写入，否则失败（rd=1 表示失败）。funct7 的 bit[1:0]（aq/rl）控制顺序语义：aq（Acquire），rl（Release）。</p></blockquote><h3 id="amo-指令-opcode-0101111" tabindex="-1">AMO 指令（opcode=0101111） <a class="header-anchor" href="#amo-指令-opcode-0101111" aria-label="Permalink to “AMO 指令（opcode=0101111）”">​</a></h3><p>每条 AMO 指令读取 M[rs1] 的旧值写入 rd，同时对内存值执行原子二元运算，将结果写回 M[rs1]。funct5 选择运算，funct3 选择数据宽度（010=.w, 011=.d）。</p><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct5</th></tr></thead><tbody><tr><td><code>amoadd.w/d rd, rs2, (rs1)</code></td><td>原子加：M += rs2</td><td>00000</td></tr><tr><td><code>amoswap.w/d rd, rs2, (rs1)</code></td><td>原子交换：M = rs2</td><td>00001</td></tr><tr><td><code>amoor.w/d rd, rs2, (rs1)</code></td><td>原子或：M |= rs2</td><td>00010</td></tr><tr><td><code>amoand.w/d rd, rs2, (rs1)</code></td><td>原子与：M &amp;= rs2</td><td>00011</td></tr><tr><td><code>amoxor.w/d rd, rs2, (rs1)</code></td><td>原子异或：M ^= rs2</td><td>00100</td></tr><tr><td><code>amomax.w/d rd, rs2, (rs1)</code></td><td>原子有符号最大：M = max(M, rs2)</td><td>01010</td></tr><tr><td><code>amomaxu.w/d rd, rs2, (rs1)</code></td><td>原子无符号最大：M = maxu(M, rs2)</td><td>01011</td></tr><tr><td><code>amomin.w/d rd, rs2, (rs1)</code></td><td>原子有符号最小：M = min(M, rs2)</td><td>01100</td></tr><tr><td><code>amominu.w/d rd, rs2, (rs1)</code></td><td>原子无符号最小：M = minu(M, rs2)</td><td>01101</td></tr></tbody></table><table tabindex="0"><thead><tr><th>A 扩展指令数</th><th>数量</th></tr></thead><tbody><tr><td>LR/SC（32+64）</td><td>4</td></tr><tr><td>AMO（9 操作 x 2 宽度）</td><td>18</td></tr><tr><td><strong>合计</strong></td><td><strong>22</strong></td></tr></tbody></table><hr><h2 id="f-扩展-单精度浮点" tabindex="-1">F 扩展：单精度浮点 <a class="header-anchor" href="#f-扩展-单精度浮点" aria-label="Permalink to “F 扩展：单精度浮点”">​</a></h2><p>F 扩展指令的 opcode 和 fmt 字段取决于指令类别。浮点通用 opcode=1010011（FP 运算），Load opcode=0000111，Store opcode=0100111。fmt 字段（inst[26:25]）：00=单精度(S)，01=双精度(D)，10=半精度(H)，11=四倍精度(Q)。</p><h3 id="浮点-load-store" tabindex="-1">浮点 Load/Store <a class="header-anchor" href="#浮点-load-store" aria-label="Permalink to “浮点 Load/Store”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>fmt</th><th>funct3</th></tr></thead><tbody><tr><td><code>flw fd, imm(rs1)</code></td><td>fd = M[rs1+imm][31:0]（单精度 load）</td><td>S</td><td>010</td></tr><tr><td><code>fsw fs2, imm(rs1)</code></td><td>M[rs1+imm][31:0] = fs2[31:0]（单精度 store）</td><td>S</td><td>010</td></tr></tbody></table><h3 id="浮点算术运算-opcode-1010011-fmt-s" tabindex="-1">浮点算术运算（opcode=1010011，fmt=S） <a class="header-anchor" href="#浮点算术运算-opcode-1010011-fmt-s" aria-label="Permalink to “浮点算术运算（opcode=1010011，fmt=S）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct5</th><th>说明</th></tr></thead><tbody><tr><td><code>fadd.s fd, fs1, fs2</code></td><td>fd = fs1 + fs2</td><td>00000</td><td>单精度加法</td></tr><tr><td><code>fsub.s fd, fs1, fs2</code></td><td>fd = fs1 - fs2</td><td>00001</td><td>单精度减法</td></tr><tr><td><code>fmul.s fd, fs1, fs2</code></td><td>fd = fs1 * fs2</td><td>00010</td><td>单精度乘法</td></tr><tr><td><code>fdiv.s fd, fs1, fs2</code></td><td>fd = fs1 / fs2</td><td>00011</td><td>单精度除法</td></tr><tr><td><code>fsqrt.s fd, fs1</code></td><td>fd = sqrt(fs1)</td><td>01011</td><td>单精度平方根（rs2=x0）</td></tr><tr><td><code>fmin.s fd, fs1, fs2</code></td><td>fd = min(fs1, fs2)</td><td>00101</td><td>单精度最小值</td></tr><tr><td><code>fmax.s fd, fs1, fs2</code></td><td>fd = max(fs1, fs2)</td><td>00101</td><td>单精度最大值（funct3=001）</td></tr><tr><td><code>fmadd.s fd, fs1, fs2, fs3</code></td><td>fd = fs1 * fs2 + fs3</td><td>—</td><td>融合乘加（opcode=1000011）</td></tr><tr><td><code>fmsub.s fd, fs1, fs2, fs3</code></td><td>fd = fs1 * fs2 - fs3</td><td>—</td><td>融合乘减（opcode=1000111）</td></tr><tr><td><code>fnmsub.s fd, fs1, fs2, fs3</code></td><td>fd = -fs1 * fs2 + fs3</td><td>—</td><td>负乘加（opcode=1001011）</td></tr><tr><td><code>fnmadd.s fd, fs1, fs2, fs3</code></td><td>fd = -fs1 * fs2 - fs3</td><td>—</td><td>负乘减（opcode=1001111）</td></tr></tbody></table><blockquote><p>FMA 指令（fmadd/fmsub/fnmsub/fnmadd）为 R4-type（4 寄存器格式），opcode 不同于普通浮点运算。</p></blockquote><h3 id="浮点转换-opcode-1010011" tabindex="-1">浮点转换（opcode=1010011） <a class="header-anchor" href="#浮点转换-opcode-1010011" aria-label="Permalink to “浮点转换（opcode=1010011）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>源 fmt</th><th>目标 fmt</th><th>funct5</th></tr></thead><tbody><tr><td><code>fcvt.w.s rd, fs1</code></td><td>rd = sign_extend(int32_t(fs1)); 向零舍入</td><td>S</td><td>W</td><td>11000</td></tr><tr><td><code>fcvt.wu.s rd, fs1</code></td><td>rd = sign_extend(uint32_t(fs1)); 向零舍入</td><td>S</td><td>WU</td><td>11000</td></tr><tr><td><code>fcvt.l.s rd, fs1</code></td><td>rd = int64_t(fs1); 向零舍入</td><td>S</td><td>L</td><td>11000</td></tr><tr><td><code>fcvt.lu.s rd, fs1</code></td><td>rd = uint64_t(fs1); 向零舍入</td><td>S</td><td>LU</td><td>11000</td></tr><tr><td><code>fcvt.s.w fd, rs1</code></td><td>fd = float32(int32_t(rs1))</td><td>W</td><td>S</td><td>11010</td></tr><tr><td><code>fcvt.s.wu fd, rs1</code></td><td>fd = float32(uint32_t(rs1))</td><td>WU</td><td>S</td><td>11010</td></tr><tr><td><code>fcvt.s.l fd, rs1</code></td><td>fd = float32(int64_t(rs1))</td><td>L</td><td>S</td><td>11010</td></tr><tr><td><code>fcvt.s.lu fd, rs1</code></td><td>fd = float32(uint64_t(rs1))</td><td>LU</td><td>S</td><td>11010</td></tr></tbody></table><h3 id="浮点比较-opcode-1010011-fmt-s" tabindex="-1">浮点比较（opcode=1010011，fmt=S） <a class="header-anchor" href="#浮点比较-opcode-1010011-fmt-s" aria-label="Permalink to “浮点比较（opcode=1010011，fmt=S）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct5</th><th>funct3</th></tr></thead><tbody><tr><td><code>fleq.s rd, fs1, fs2</code></td><td>rd = (fs1 == fs2) ? 1 : 0</td><td>10100</td><td>010</td></tr><tr><td><code>fltq.s rd, fs1, fs2</code></td><td>rd = (fs1 &lt; fs2) ? 1 : 0</td><td>10100</td><td>001</td></tr><tr><td><code>fle.s rd, fs1, fs2</code></td><td>rd = (fs1 &lt;= fs2) ? 1 : 0</td><td>10100</td><td>000</td></tr></tbody></table><h3 id="浮点移动-opcode-1010011" tabindex="-1">浮点移动（opcode=1010011） <a class="header-anchor" href="#浮点移动-opcode-1010011" aria-label="Permalink to “浮点移动（opcode=1010011）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct5</th><th>说明</th></tr></thead><tbody><tr><td><code>fsgnj.s fd, fs1, fs2</code></td><td>fd = {fs2[31], fs1[30:0]}（符号注入）</td><td>00100</td><td>funct3=000</td></tr><tr><td><code>fsgnjn.s fd, fs1, fs2</code></td><td>fd = {~fs2[31], fs1[30:0]}（负符号注入）</td><td>00100</td><td>funct3=001</td></tr><tr><td><code>fsgnjx.s fd, fs1, fs2</code></td><td>fd = {fs1[31]^fs2[31], fs1[30:0]}（异或符号注入）</td><td>00100</td><td>funct3=010</td></tr><tr><td><code>fclass.s rd, fs1</code></td><td>rd = 分类结果（10 类编码）</td><td>11100</td><td>funct3=001</td></tr><tr><td><code>fmv.x.w rd, fs1</code></td><td>rd = sign_extend(fs1[31:0])（FP→整数）</td><td>11100</td><td>funct3=000</td></tr></tbody></table><hr><h2 id="d-扩展-双精度浮点" tabindex="-1">D 扩展：双精度浮点 <a class="header-anchor" href="#d-扩展-双精度浮点" aria-label="Permalink to “D 扩展：双精度浮点”">​</a></h2><p>D 扩展在 F 基础上增加双精度（64 位）指令。fmt=01（D）。包含所有 F 扩展指令的双精度版本。</p><h3 id="浮点-load-store-双精度" tabindex="-1">浮点 Load/Store（双精度） <a class="header-anchor" href="#浮点-load-store-双精度" aria-label="Permalink to “浮点 Load/Store（双精度）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>fmt</th><th>funct3</th></tr></thead><tbody><tr><td><code>fld fd, imm(rs1)</code></td><td>fd = M[rs1+imm][63:0]（双精度 load）</td><td>D</td><td>011</td></tr><tr><td><code>fsd fs2, imm(rs1)</code></td><td>M[rs1+imm][63:0] = fs2[63:0]（双精度 store）</td><td>D</td><td>011</td></tr></tbody></table><h3 id="浮点算术运算-fmt-d" tabindex="-1">浮点算术运算（fmt=D） <a class="header-anchor" href="#浮点算术运算-fmt-d" aria-label="Permalink to “浮点算术运算（fmt=D）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>funct5</th></tr></thead><tbody><tr><td><code>fadd.d fd, fs1, fs2</code></td><td>fd = fs1 + fs2（双精度）</td><td>00000</td></tr><tr><td><code>fsub.d fd, fs1, fs2</code></td><td>fd = fs1 - fs2（双精度）</td><td>00001</td></tr><tr><td><code>fmul.d fd, fs1, fs2</code></td><td>fd = fs1 * fs2（双精度）</td><td>00010</td></tr><tr><td><code>fdiv.d fd, fs1, fs2</code></td><td>fd = fs1 / fs2（双精度）</td><td>00011</td></tr><tr><td><code>fsqrt.d fd, fs1</code></td><td>fd = sqrt(fs1)（双精度）</td><td>01011</td></tr><tr><td><code>fmin.d fd, fs1, fs2</code></td><td>fd = min(fs1, fs2)（双精度）</td><td>00101</td></tr><tr><td><code>fmax.d fd, fs1, fs2</code></td><td>fd = max(fs1, fs2)（双精度）</td><td>00101</td></tr><tr><td><code>fmadd.d fd, fs1, fs2, fs3</code></td><td>fd = fs1 * fs2 + fs3（FMA）</td><td>—</td></tr><tr><td><code>fmsub.d fd, fs1, fs2, fs3</code></td><td>fd = fs1 * fs2 - fs3</td><td>—</td></tr><tr><td><code>fnmsub.d fd, fs1, fs2, fs3</code></td><td>fd = -fs1 * fs2 + fs3</td><td>—</td></tr><tr><td><code>fnmadd.d fd, fs1, fs2, fs3</code></td><td>fd = -fs1 * fs2 - fs3</td><td>—</td></tr></tbody></table><h3 id="浮点转换-d-扩展" tabindex="-1">浮点转换（D 扩展） <a class="header-anchor" href="#浮点转换-d-扩展" aria-label="Permalink to “浮点转换（D 扩展）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>源 fmt</th><th>目标 fmt</th><th>funct5</th></tr></thead><tbody><tr><td><code>fcvt.d.s fd, fs1</code></td><td>fd = float64(float32(fs1))</td><td>S</td><td>D</td><td>01000</td></tr><tr><td><code>fcvt.s.d fd, fs1</code></td><td>fd = float32(float64(fs1))</td><td>D</td><td>S</td><td>01000</td></tr><tr><td><code>fcvt.w.d rd, fs1</code></td><td>rd = sign_extend(int32_t(fs1)); 向零舍入</td><td>D</td><td>W</td><td>11000</td></tr><tr><td><code>fcvt.wu.d rd, fs1</code></td><td>rd = sign_extend(uint32_t(fs1)); 向零舍入</td><td>D</td><td>WU</td><td>11000</td></tr><tr><td><code>fcvt.l.d rd, fs1</code></td><td>rd = int64_t(fs1); 向零舍入</td><td>D</td><td>L</td><td>11000</td></tr><tr><td><code>fcvt.lu.d rd, fs1</code></td><td>rd = uint64_t(fs1); 向零舍入</td><td>D</td><td>LU</td><td>11000</td></tr><tr><td><code>fcvt.d.w fd, rs1</code></td><td>fd = float64(int32_t(rs1))</td><td>W</td><td>D</td><td>11010</td></tr><tr><td><code>fcvt.d.wu fd, rs1</code></td><td>fd = float64(uint32_t(rs1))</td><td>WU</td><td>D</td><td>11010</td></tr><tr><td><code>fcvt.d.l fd, rs1</code></td><td>fd = float64(int64_t(rs1))</td><td>L</td><td>D</td><td>11010</td></tr><tr><td><code>fcvt.d.lu fd, rs1</code></td><td>fd = float64(uint64_t(rs1))</td><td>LU</td><td>D</td><td>11010</td></tr></tbody></table><h3 id="浮点比较与移动-fmt-d" tabindex="-1">浮点比较与移动（fmt=D） <a class="header-anchor" href="#浮点比较与移动-fmt-d" aria-label="Permalink to “浮点比较与移动（fmt=D）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>fmt</th></tr></thead><tbody><tr><td><code>fleq.d rd, fs1, fs2</code></td><td>rd = (fs1 == fs2) ? 1 : 0</td><td>D</td></tr><tr><td><code>fltq.d rd, fs1, fs2</code></td><td>rd = (fs1 &lt; fs2) ? 1 : 0</td><td>D</td></tr><tr><td><code>fle.d rd, fs1, fs2</code></td><td>rd = (fs1 &lt;= fs2) ? 1 : 0</td><td>D</td></tr><tr><td><code>fsgnj.d fd, fs1, fs2</code></td><td>符号注入（同 S）</td><td>D</td></tr><tr><td><code>fsgnjn.d fd, fs1, fs2</code></td><td>负符号注入</td><td>D</td></tr><tr><td><code>fsgnjx.d fd, fs1, fs2</code></td><td>异或符号注入</td><td>D</td></tr><tr><td><code>fclass.d rd, fs1</code></td><td>双精度分类</td><td>D</td></tr><tr><td><code>fmv.d fd, fs</code></td><td>双精度浮点寄存器间移动</td><td>D</td></tr><tr><td><code>fmv.x.d rd, fs1</code></td><td>rd = fs1[63:0]（FP→整数，64 位）</td><td>D</td></tr></tbody></table><h3 id="浮点寄存器移动-跨类型" tabindex="-1">浮点寄存器移动（跨类型） <a class="header-anchor" href="#浮点寄存器移动-跨类型" aria-label="Permalink to “浮点寄存器移动（跨类型）”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>操作语义</th><th>fmt</th></tr></thead><tbody><tr><td><code>fmv.w.x fd, rs1</code></td><td>fd[31:0] = rs1[31:0]; fd[63:32]=1s（整数→SP）</td><td>S</td></tr><tr><td><code>fmv.d.x fd, rs1</code></td><td>fd = rs1（整数→DP）</td><td>D</td></tr></tbody></table><blockquote><p><strong>F/D 扩展依赖关系</strong>：D 扩展必然包含 F 扩展。实现 D 必须同时支持 S 精度指令。</p></blockquote><hr><h2 id="c-扩展-压缩指令" tabindex="-1">C 扩展：压缩指令 <a class="header-anchor" href="#c-扩展-压缩指令" aria-label="Permalink to “C 扩展：压缩指令”">​</a></h2><p>C 扩展提供 16 位压缩编码，缩小代码体积。每条 C 指令有对应的 32 位等效指令。压缩指令的 opcode 位于 [1:0] 位。</p><h3 id="quadrant-0-opcode-1-0-00-c0-指令" tabindex="-1">Quadrant 0（opcode[1:0]=00）：C0 指令 <a class="header-anchor" href="#quadrant-0-opcode-1-0-00-c0-指令" aria-label="Permalink to “Quadrant 0（opcode[1:0]=00）：C0 指令”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>编码含义</th><th>16 位指令</th><th>32 位等效</th></tr></thead><tbody><tr><td><code>c.addi4spn rd&#39;, imm</code></td><td>栈指针加立即数（imm≠0, rd&#39;=x8-x15）</td><td>000_0_xxx_xxxxxxx_00</td><td>addi rd&#39;, sp, imm*4</td></tr><tr><td><code>c.fld rd&#39;, imm(rs1&#39;)</code></td><td>双精度 load</td><td>001_xxx_xxxxxxx_00</td><td>fld rd&#39;, imm*8(rs1&#39;)</td></tr><tr><td><code>c.lw rd&#39;, imm(rs1&#39;)</code></td><td>32 位 load</td><td>010_xxx_xxxxxxx_00</td><td>lw rd&#39;, imm*4(rs1&#39;)</td></tr><tr><td><code>c.ld rd&#39;, imm(rs1&#39;)</code></td><td>64 位 load</td><td>011_xxx_xxxxxxx_00</td><td>ld rd&#39;, imm*8(rs1&#39;)</td></tr><tr><td><code>c.fsd rs2&#39;, imm(rs1&#39;)</code></td><td>双精度 store</td><td>101_xxx_xxxxxxx_00</td><td>fsd rs2&#39;, imm*8(rs1&#39;)</td></tr><tr><td><code>c.sw rs2&#39;, imm(rs1&#39;)</code></td><td>32 位 store</td><td>110_xxx_xxxxxxx_00</td><td>sw rs2&#39;, imm*4(rs1&#39;)</td></tr><tr><td><code>c.sd rs2&#39;, imm(rs1&#39;)</code></td><td>64 位 store</td><td>111_xxx_xxxxxxx_00</td><td>sd rs2&#39;, imm*8(rs1&#39;)</td></tr><tr><td><code>c.addi4spn rd&#39;, nzuimm</code></td><td>栈偏移地址（立即数零扩展，nz）</td><td>—</td><td>addi rd&#39;, sp, nzuimm</td></tr></tbody></table><blockquote><p><strong>寄存器编码</strong>：rd&#39; 和 rs1&#39; 使用 3 位编码（000=x8, 001=x9, ..., 111=x15）。</p></blockquote><h3 id="quadrant-1-opcode-1-0-01-c1-指令" tabindex="-1">Quadrant 1（opcode[1:0]=01）：C1 指令 <a class="header-anchor" href="#quadrant-1-opcode-1-0-01-c1-指令" aria-label="Permalink to “Quadrant 1（opcode[1:0]=01）：C1 指令”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>编码含义</th><th>32 位等效</th></tr></thead><tbody><tr><td><code>c.addi rd, imm</code></td><td>rd=rd+imm（rd≠x0，imm≠0）</td><td>addi rd, rd, imm</td></tr><tr><td><code>c.addiw rd, imm</code></td><td>32 位加法（rd≠x0）</td><td>addiw rd, rd, imm</td></tr><tr><td><code>c.jal add</code></td><td>带链接跳转（RV32）</td><td>jal x1, offset</td></tr><tr><td><code>c.li rd, imm</code></td><td>加载立即数（rd≠x0）</td><td>addi rd, x0, imm</td></tr><tr><td><code>c.lui rd, imm</code></td><td>加载高立即数（rd≠{x0,x2}，imm≠0）</td><td>lui rd, imm</td></tr><tr><td><code>c.addi16sp imm</code></td><td>sp=sp+imm（imm≠0，16 字节对齐）</td><td>addi sp, sp, imm</td></tr><tr><td><code>c.srli rd&#39;, imm</code></td><td>逻辑右移（rd&#39;=x8-x15）</td><td>srli rd&#39;, rd&#39;, imm</td></tr><tr><td><code>c.srai rd&#39;, imm</code></td><td>算术右移</td><td>srai rd&#39;, rd&#39;, imm</td></tr><tr><td><code>c.andi rd&#39;, imm</code></td><td>按位与</td><td>andi rd&#39;, rd&#39;, imm</td></tr><tr><td><code>c.sub rd&#39;, rs2&#39;</code></td><td>减法</td><td>sub rd&#39;, rd&#39;, rs2&#39;</td></tr><tr><td><code>c.xor rd&#39;, rs2&#39;</code></td><td>异或</td><td>xor rd&#39;, rd&#39;, rs2&#39;</td></tr><tr><td><code>c.or rd&#39;, rs2&#39;</code></td><td>按位或</td><td>or rd&#39;, rd&#39;, rs2&#39;</td></tr><tr><td><code>c.and rd&#39;, rs2&#39;</code></td><td>按位与</td><td>and rd&#39;, rd&#39;, rs2&#39;</td></tr><tr><td><code>c.j offset</code></td><td>无条件跳转</td><td>jal x0, offset</td></tr><tr><td><code>c.beqz rs1&#39;, offset</code></td><td>为零跳转</td><td>beq rs1&#39;, x0, offset</td></tr><tr><td><code>c.bnez rs1&#39;, offset</code></td><td>非零跳转</td><td>bne rs1&#39;, x0, offset</td></tr></tbody></table><h3 id="quadrant-2-opcode-1-0-10-c2-指令" tabindex="-1">Quadrant 2（opcode[1:0]=10）：C2 指令 <a class="header-anchor" href="#quadrant-2-opcode-1-0-10-c2-指令" aria-label="Permalink to “Quadrant 2（opcode[1:0]=10）：C2 指令”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>编码含义</th><th>32 位等效</th></tr></thead><tbody><tr><td><code>c.slli rd, imm</code></td><td>逻辑左移（rd≠x0，imm≠0）</td><td>slli rd, rd, imm</td></tr><tr><td><code>c.fldsp fd, imm(sp)</code></td><td>双精度 FP load（相对 sp）</td><td>fld fd, imm(sp)</td></tr><tr><td><code>c.lwsp rd, imm(sp)</code></td><td>32 位 load（rd≠x0）</td><td>lw rd, imm(sp)</td></tr><tr><td><code>c.ldsp rd, imm(sp)</code></td><td>64 位 load（rd≠x0）</td><td>ld rd, imm(sp)</td></tr><tr><td><code>c.jr rs1</code></td><td>跳转至寄存器（rs1≠x0）</td><td>jalr x0, rs1, 0</td></tr><tr><td><code>c.mv rd, rs2</code></td><td>寄存器移动（rd≠x0，rs2≠x0）</td><td>add rd, x0, rs2</td></tr><tr><td><code>c.ebreak</code></td><td>断点</td><td>ebreak</td></tr><tr><td><code>c.jalr rs1</code></td><td>带链接跳转（rs1≠x0）</td><td>jalr x1, rs1, 0</td></tr><tr><td><code>c.add rd, rs2</code></td><td>加法（rd≠x0，rs2≠x0）</td><td>add rd, rd, rs2</td></tr><tr><td><code>c.fsdsp fs2, imm(sp)</code></td><td>双精度 FP store（相对 sp）</td><td>fsd fs2, imm(sp)</td></tr><tr><td><code>c.swsp rs2, imm(sp)</code></td><td>32 位 store</td><td>sw rs2, imm(sp)</td></tr><tr><td><code>c.sdsp rs2, imm(sp)</code></td><td>64 位 store</td><td>sd rs2, imm(sp)</td></tr></tbody></table><blockquote><p><strong>压缩指令注意</strong>：寄存器编码有限（3 位或 5 位），立即数范围受限。压缩指令总是对应唯一的 32 位指令，由汇编器自动选择。编写汇编时直接使用 32 位伪指令或伪指令即可，汇编器会尽可能生成压缩编码以减小代码尺寸。</p></blockquote><h3 id="c-扩展寄存器编码" tabindex="-1">C 扩展寄存器编码 <a class="header-anchor" href="#c-扩展寄存器编码" aria-label="Permalink to “C 扩展寄存器编码”">​</a></h3><table tabindex="0"><thead><tr><th>3 位编码 (rd&#39;/rs&#39;)</th><th>寄存器</th><th>说明</th></tr></thead><tbody><tr><td>000</td><td>x8 (s0)</td><td>C0/C1 中使用的 rd&#39;/rs&#39; 寄存器组</td></tr><tr><td>001</td><td>x9 (s1)</td><td></td></tr><tr><td>010</td><td>x10 (a0)</td><td></td></tr><tr><td>011</td><td>x11 (a1)</td><td></td></tr><tr><td>100</td><td>x12 (a2)</td><td></td></tr><tr><td>101</td><td>x13 (a3)</td><td></td></tr><tr><td>110</td><td>x14 (a4)</td><td></td></tr><tr><td>111</td><td>x15 (a5)</td><td></td></tr></tbody></table><table tabindex="0"><thead><tr><th>5 位编码 (rd/rs)</th><th>可用的寄存器</th></tr></thead><tbody><tr><td>5-bit</td><td>x0-x31 全范围</td></tr></tbody></table><hr><h2 id="扩展速查总结" tabindex="-1">扩展速查总结 <a class="header-anchor" href="#扩展速查总结" aria-label="Permalink to “扩展速查总结”">​</a></h2><table tabindex="0"><thead><tr><th>扩展名</th><th>描述</th><th>指令数（约）</th><th>依赖</th></tr></thead><tbody><tr><td><strong>M</strong></td><td>整数乘除法</td><td>8 + 5(W) = 13</td><td>—</td></tr><tr><td><strong>A</strong></td><td>原子操作</td><td>4(LR/SC) + 18(AMO) = 22</td><td>—</td></tr><tr><td><strong>F</strong></td><td>单精度浮点</td><td>~30（含 FMA/转换/比较）</td><td>—</td></tr><tr><td><strong>D</strong></td><td>双精度浮点</td><td>~30（含转换/比较/移动）</td><td>F</td></tr><tr><td><strong>C</strong></td><td>压缩指令</td><td>~27（16 位编码）</td><td>—</td></tr></tbody></table><blockquote><p>RISC-V 常见组合：<strong>RV64IMA</strong>（嵌入式）、<strong>RV64IMAFD</strong>（通用计算，又名 RV64G）、<strong>RV64IMAFDC</strong>（含压缩指令，又名 RV64GC）。</p></blockquote>',65))])}]]);export{c as __pageData,h as default};
